// Smart router: if body has a 'message' or 'text' field (natural language from DAX)
// we need AI extraction. If it already has 'clientName' and 'firmName' structured fields,
// pass through directly.
const body = $input.first().json.body || {};

const isNaturalLanguage = !!(body.message || body.text || body.input) && !body.clientName;
const isStructured = !!(body.clientName && body.firmName);

return [{
  json: {
    ...body,
    _routeToAI: isNaturalLanguage,
    _inputText: body.message || body.text || body.input || '',
    _isStructured: isStructured
  }
}];

// Merge AI-extracted fields with any structured fields already in the webhook body
// If AI ran, parse its output. If structured input, use directly.
const routedData = $('Route Input').first().json;
const isStructured = routedData._isStructured;

let fields = {};

if (isStructured) {
  // Already structured - pass through directly
  fields = routedData;
} else {
  // Parse AI agent output
  const agentOutput = $('AI Field Extractor').first().json.output || '';
  try {
    // Strip markdown code blocks if present
    const cleaned = agentOutput.replace(/```json|```/g, '').trim();
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      fields = JSON.parse(jsonMatch[0]);
    }
  } catch(e) {
    console.log('AI output parse error:', e.message);
    console.log('Raw AI output:', agentOutput);
  }
}

// Apply defaults for missing required fields
const today = new Date().toISOString().split('T')[0];
const currentQuarter = 'Q' + Math.ceil((new Date().getMonth() + 1) / 3) + ' ' + new Date().getFullYear();

return [{
  json: {
    firmName: fields.firmName || routedData.firmName || 'Dakona Advisory',
    clientName: fields.clientName || routedData.clientName || 'Client',
    reportPeriod: fields.reportPeriod || routedData.reportPeriod || currentQuarter,
    reportDate: fields.reportDate || routedData.reportDate || today,
    advisorName: fields.advisorName || routedData.advisorName || 'Your Advisor',
    accountNumber: fields.accountNumber || routedData.accountNumber || '',
    accountType: fields.accountType || routedData.accountType || 'Investment Account',
    riskProfile: fields.riskProfile || routedData.riskProfile || 'Moderate',
    meetingDate: fields.meetingDate || routedData.meetingDate || today,
    meetingLocation: fields.meetingLocation || routedData.meetingLocation || 'Zoom',
    attendees: fields.attendees || routedData.attendees || fields.advisorName || '',
    meetingDuration: fields.meetingDuration || routedData.meetingDuration || '60 min',
    discussionPoint1: fields.discussionPoint1 || routedData.discussionPoint1 || '',
    discussionPoint2: fields.discussionPoint2 || routedData.discussionPoint2 || '',
    discussionPoint3: fields.discussionPoint3 || routedData.discussionPoint3 || '',
    advisorNotes: fields.advisorNotes || routedData.advisorNotes || '',
    portfolioValue: fields.portfolioValue || routedData.portfolioValue || '',
    ytdReturn: fields.ytdReturn || routedData.ytdReturn || '',
    benchmarkReturn: fields.benchmarkReturn || routedData.benchmarkReturn || '',
    vsBenchmark: fields.vsBenchmark || routedData.vsBenchmark || '',
    goal1: fields.goal1 || routedData.goal1 || '',
    goal2: fields.goal2 || routedData.goal2 || '',
    goal3: fields.goal3 || routedData.goal3 || '',
    goalsProgressNotes: fields.goalsProgressNotes || routedData.goalsProgressNotes || '',
    action1: fields.action1 || routedData.action1 || '',
    action1Owner: fields.action1Owner || routedData.action1Owner || '',
    action1Due: fields.action1Due || routedData.action1Due || '',
    action2: fields.action2 || routedData.action2 || '',
    action2Owner: fields.action2Owner || routedData.action2Owner || '',
    action2Due: fields.action2Due || routedData.action2Due || '',
    action3: fields.action3 || routedData.action3 || '',
    action3Owner: fields.action3Owner || routedData.action3Owner || '',
    action3Due: fields.action3Due || routedData.action3Due || '',
    nextMeetingDate: fields.nextMeetingDate || routedData.nextMeetingDate || '',
    nextMeetingAgenda: fields.nextMeetingAgenda || routedData.nextMeetingAgenda || ''
  }
}];

const https = require('https');
const { execFileSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

// Use merged/AI-extracted data from Merge Fields node
const data = $('Merge Fields').first().json;

// --- Step 1: Download template via pre-authenticated URL ---
const downloadUrl = $('Get Download URL').first().json['@microsoft.graph.downloadUrl'];
console.log('Download URL obtained, fetching template...');

const templateBuffer = await new Promise((resolve, reject) => {
  https.get(downloadUrl, (res) => {
    if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
      https.get(res.headers.location, (redirectRes) => {
        const chunks = [];
        redirectRes.on('data', chunk => chunks.push(chunk));
        redirectRes.on('end', () => resolve(Buffer.concat(chunks)));
        redirectRes.on('error', reject);
      }).on('error', reject);
      return;
    }
    const chunks = [];
    res.on('data', chunk => chunks.push(chunk));
    res.on('end', () => resolve(Buffer.concat(chunks)));
    res.on('error', reject);
  }).on('error', reject);
});
console.log('Template buffer: ' + templateBuffer.length + ' bytes');

if (templateBuffer.length < 1000) {
  throw new Error('Template too small (' + templateBuffer.length + ' bytes). Expected ~15kB docx file.');
}

// --- Step 2: Map fields to UPPER_SNAKE template tags ---
const templateData = {
  FIRM_NAME: data.firmName || '',
  CLIENT_NAME: data.clientName || '',
  REPORT_PERIOD: data.reportPeriod || '',
  REPORT_DATE: data.reportDate || '',
  ADVISOR_NAME: data.advisorName || '',
  MEETING_DATE: data.meetingDate || '',
  MEETING_LOCATION: data.meetingLocation || '',
  ATTENDEES: data.attendees || '',
  MEETING_DURATION: data.meetingDuration || '',
  DISCUSSION_POINT_1: data.discussionPoint1 || '',
  DISCUSSION_POINT_2: data.discussionPoint2 || '',
  DISCUSSION_POINT_3: data.discussionPoint3 || '',
  ADVISOR_NOTES: data.advisorNotes || '',
  PORTFOLIO_VALUE: data.portfolioValue || '',
  YTD_RETURN: data.ytdReturn || '',
  BENCHMARK_RETURN: data.benchmarkReturn || '',
  VS_BENCHMARK: data.vsBenchmark || '',
  GOAL_1: data.goal1 || '',
  GOAL_2: data.goal2 || '',
  GOAL_3: data.goal3 || '',
  GOALS_PROGRESS_NOTES: data.goalsProgressNotes || '',
  ACTION_1: data.action1 || '',
  ACTION_1_OWNER: data.action1Owner || '',
  ACTION_1_DUE: data.action1Due || '',
  ACTION_2: data.action2 || '',
  ACTION_2_OWNER: data.action2Owner || '',
  ACTION_2_DUE: data.action2Due || '',
  ACTION_3: data.action3 || '',
  ACTION_3_OWNER: data.action3Owner || '',
  ACTION_3_DUE: data.action3Due || '',
  NEXT_MEETING_DATE: data.nextMeetingDate || '',
  NEXT_MEETING_AGENDA: data.nextMeetingAgenda || '',
  ACCOUNT_NUMBER: data.accountNumber || '',
  ACCOUNT_TYPE: data.accountType || '',
  RISK_PROFILE: data.riskProfile || '',
};

// --- Step 3: Write temp files and run docxtemplater ---
const ts = Date.now();
const tmpDir = os.tmpdir();
const tplPath = path.join(tmpDir, 'docgen-tpl-' + ts + '.docx');
const dataPath = path.join(tmpDir, 'docgen-data-' + ts + '.json');
const scriptPath = path.join(tmpDir, 'docgen-script-' + ts + '.js');

fs.writeFileSync(tplPath, templateBuffer);
fs.writeFileSync(dataPath, JSON.stringify(templateData));

const script = `
const PizZip = require('pizzip');
const Docxtemplater = require('docxtemplater');
const InspectModule = require('docxtemplater/js/inspect-module.js');
const fs = require('fs');

const tplBuf = fs.readFileSync(process.argv[2]);
const data = JSON.parse(fs.readFileSync(process.argv[3], 'utf8'));

const inspectZip = new PizZip(tplBuf);
const iModule = new InspectModule();
try {
  const inspectDoc = new Docxtemplater(inspectZip, {
    modules: [iModule],
    delimiters: { start: '{{', end: '}}' },
  });
} catch (e) {}
const allTags = iModule.getAllTags();
const tagNames = Object.keys(allTags);
console.error('TEMPLATE TAGS FOUND (' + tagNames.length + '): ' + tagNames.join(', '));

const zip = new PizZip(tplBuf);
const doc = new Docxtemplater(zip, {
  delimiters: { start: '{{', end: '}}' },
  paragraphLoop: true,
  linebreaks: true,
  nullGetter(part) {
    if (!part.module) console.error('UNRESOLVED TAG: ' + part.value);
    return '';
  },
});

doc.render(data);
const buf = doc.getZip().generate({ type: 'nodebuffer', compression: 'DEFLATE' });
process.stdout.write(buf.toString('base64'));
`;
fs.writeFileSync(scriptPath, script);

let outputBase64;
try {
  outputBase64 = execFileSync('node', [scriptPath, tplPath, dataPath], {
    maxBuffer: 50 * 1024 * 1024,
    encoding: 'utf8',
    stdio: ['pipe', 'pipe', 'pipe'],
  });
} catch (execErr) {
  if (execErr.stderr) console.log('Helper stderr:\n' + execErr.stderr.toString());
  throw new Error('docxtemplater failed: ' + (execErr.stderr ? execErr.stderr.toString() : execErr.message));
} finally {
  try { fs.unlinkSync(tplPath); } catch (_) {}
  try { fs.unlinkSync(dataPath); } catch (_) {}
  try { fs.unlinkSync(scriptPath); } catch (_) {}
}

const fileName = (data.CLIENT_NAME || 'Report').replace(/[^a-zA-Z0-9\s-]/g, '') + '-' + (data.REPORT_PERIOD || 'Report').replace(/[^a-zA-Z0-9\s-]/g, '') + '.docx';

return [{
  binary: {
    data: {
      data: outputBase64,
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      fileName: fileName,
      fileExtension: 'docx'
    }
  },
  json: { fileName: fileName }
}];
